## Code Example

```javascript
function dfs(u, k, val, children, dp) {
  let f = Array(k+1).fill(-Infinity);
  f[0] = 0;
  for (const v of children[u]) {
    let g = Array(k+1).fill(-Infinity);
    for (let i = 0; i <= k; i++) {
      if (f[i] <= -Infinity) continue;
      for (let t = 0; t + i <= k; t++) {
        g[i+t] = Math.max(g[i+t], f[i] + dp[v][t]);
      }
    }
    f = g;
  }
  for (let t = 0; t <= k; t++) dp[u][t] = f[t] + t * val[u];
}
```

