function maxKOrSubarrays(A, k){
  const n=A.length;
  const dp=Array.from({length:n+1}, ()=> Array(k+1).fill(-Infinity));
  const prv=Array.from({length:n+1}, ()=> Array(k+1).fill(-1));
  dp[0][0]=0;
  for(let i=0;i<n;i++){
    for(let t=1;t<=k;t++){
      let curr=0;
      for(let j=i;j>=0;j--){
        curr |= A[j];
        let left = dp[j][t-1];
        if(left>-Infinity){
          const cand = left + curr;
          if(cand>dp[i+1][t]){ dp[i+1][t]=cand; prv[i+1][t]=j; }
        }
      }
    }
  }
  return {value: dp[n][k], endAt: prv};
}
```

