## Code Example
```javascript
function maxPathWithBoosts(grid, boost, K){
  const n = grid.length, m = grid[0].length;
  const neg = -1e15;
  const dp = Array.from({length:n}, () => Array.from({length:m}, () => Array(K+1).fill(neg)));
  const par = Array.from({length:n}, () => Array.from({length:m}, () => Array(K+1).fill(null)));
  const b00 = boost[0][0] ? 1 : 0;
  dp[0][0][b00] = grid[0][0];
  for (let i=0;i<n;i++){
    for (let j=0;j<m;j++){
      for (let t=0;t<=K;t++){
        const add = boost[i][j] ? 1 : 0;
        if (i===0 && j===0) continue;
        const candFromTop = i>0 ? dp[i-1][j][t - add] : neg;
        const candFromLeft = j>0 ? dp[i][j-1][t - add] : neg;
        const bestPrev = Math.max(candFromTop, candFromLeft);
        if (bestPrev > neg/2) {
          dp[i][j][t] = bestPrev + grid[i][j];
          par[i][j][t] = candFromTop >= candFromLeft ? ['top'] : ['left'];
        }
      }
    }
  }
  // Reconstruction omitted for brevity
  return {best: dp[n-1][m-1][K], path: []};
}
```

