function minCostPartitions(A, k) {
  const n = A.length;
  const dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(Infinity));
  const pre = Array.from({ length: n + 1 }, () => Array(k + 1).fill(-1));

  dp[0][0] = 0;

  // Base case: single segment
  for (let i = 1; i <= n; i++) {
    let maxVal = A[0], minVal = A[0];
    for (let j = 0; j < i; j++) {
      maxVal = Math.max(maxVal, A[j]);
      minVal = Math.min(minVal, A[j]);
      dp[i][1] = maxVal - minVal;
    }
  }

  // DP transitions
  for (let t = 2; t <= k; t++) {
    for (let i = 1; i <= n; i++) {
      for (let j = t - 1; j < i; j++) {
        const segmentCost = computeCost(A, j + 1, i);
        if (dp[j][t - 1] + segmentCost < dp[i][t]) {
          dp[i][t] = dp[j][t - 1] + segmentCost;
          pre[i][t] = j;
        }
      }
    }
  }

  // Reconstruct segments
  const segments = [];
  let end = n;
  for (let t = k; t >= 1; t--) {
    const start = pre[end][t] + 1;
    segments.unshift([start, end]);
    end = pre[end][t];
  }

  return { minCost: dp[n][k], segments };
}
```

