function maxPathWithTurns(grid, k){
  const n = grid.length, m = grid[0].length;
  const NEG = -1e15;
  const dp = Array.from({length:n}, ()=>
    Array.from({length:m}, ()=>
      Array.from({length:k+1}, ()=> Array(2).fill(NEG))))
  dp[0][0][0][0] = grid[0][0];
  dp[0][0][0][1] = grid[0][0];
  for(let i=0;i<n;i++){
    for(let j=0;j<m;j++){
      for(let t=0;t<=k;t++){
        for(let dir=0;dir<2;dir++){
          const cur = dp[i][j][t][dir];
          if(cur===NEG) continue;
          // move right
          if(j+1<m){
            const nt = t + (dir===0?0:1);
            if(nt<=k) dp[i][j+1][nt][0] = Math.max(dp[i][j+1][nt][0], cur + grid[i][j+1]);
          }
          // move down
          if(i+1<n){
            const nt = t + (dir===1?0:1);
            if(nt<=k) dp[i+1][j][nt][1] = Math.max(dp[i+1][j][nt][1], cur + grid[i+1][j]);
          }
        }
      }
    }
  }
  let ans = NEG;
  for(let t=0;t<=k;t++){
    ans = Math.max(ans, dp[n-1][m-1][t][0], dp[n-1][m-1][t][1]);
  }
  return ans;
}
