// Implementation sketch
function maxKSubstrings(s, k) {
  const n = s.length;
  const dist = Array.from({length: n}, () => Array(n).fill(0));
  for (let i = 0; i < n; i++) {
    const freq = new Array(26).fill(0);
    let setBits = 0;
    for (let j = i; j >= 0; j--) {
      const idx = s.charCodeAt(j) - 97;
      if (freq[idx]++ === 0) setBits++;
      dist[j][i] = setBits;
    }
  }

  const dp = Array.from({length: n+1}, () => Array(k+1).fill(-Infinity));
  const prev = Array.from({length: n+1}, () => Array(k+1).fill(-1));
  const start = Array.from({length: n+1}, () => Array(k+1).fill(-1));

  dp[0][0] = 0;

  for (let i = 1; i <= n; i++) {
    dp[i][0] = 0;
    for (let t = 1; t <= k; t++) {
      // Option 1: skip i
      if (dp[i-1][t] > dp[i][t]) {
        dp[i][t] = dp[i-1][t];
        prev[i][t] = i-1;
        start[i][t] = start[i-1][t];
      }

      // Option 2: end t-th substring at i
      for (let s = 1; s <= i; s++) {
        const val = dp[s-1][t-1] + dist[s-1][i-1];
        if (val > dp[i][t]) {
          dp[i][t] = val;
          prev[i][t] = s-1;
          start[i][t] = s-1;
        }
      }
    }
  }

  // Reconstruct substrings
  const result = [];
  let i = n, t = k;
  while (t > 0 && i > 0) {
    if (prev[i][t] === i-1) {
      i--;
    } else {
      result.unshift([start[i][t]+1, i]);
      i = prev[i][t];
      t--;
    }
  }

  return { maxValue: dp[n][k], substrings: result };
}
```

Time complexity: O(n²k) for DP transitions + O(n²) for preprocessing. Space: O(n² + nk). Optimizations include limiting the inner loop or using convex hull tricks for special cases.

