  const from = Array.from({length: n+1}, () => new Array(k+1).fill(null));
  dp[0][0] = 0;
  const bestVal = new Array(k+1).fill(NEG);
  const bestIdx = new Array(k+1).fill(-1);
  for (let i = 1; i <= n; i++){
    for (let t = 0; t <= k; t++){
      dp[i][t] = dp[i-1][t];
      from[i][t] = {type:'skip', at:i-1, t};
    }
    for (let t = 1; t <= k; t++){
      const val = dp[i-1][t-1] - pref[i-1];
      if (val > bestVal[t]) { bestVal[t] = val; bestIdx[t] = i-1; }
      const cand = bestVal[t] + pref[i] - c;
      if (cand > dp[i][t]) {
        dp[i][t] = cand;
        from[i][t] = {type:'end', end:i-1, start:bestIdx[t], t};
      }
    }
  }
  let i = n, t = k;
  const blocks = [];
  while (i > 0 && t > 0){
    const info = from[i][t];
    if (!info) break;
    if (info.type === 'end'){
      blocks.push([info.start, info.end]);
      i = info.start;
      t--;
    } else {
      i = info.at;
    }
  }
  blocks.reverse();
  return { value: dp[n][k], blocks };
}
```

