function maxScore(A, k) {
  const n = A.length;
  const NEG = -1e15;
  const dp = Array.from({length: n+1}, () => Array(k+1).fill(NEG));
  const parent = Array.from({length: n+1}, () => Array(k+1).fill(-1));

  dp[0][0] = 0;

  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= k; t++) {
      let curMax = -INF, curMin = INF;
      for (let l = i; l >= 1; l--) {
        curMax = Math.max(curMax, A[l-1]);
        curMin = Math.min(curMin, A[l-1]);
        const blockScore = (curMax - curMin) * (i - l + 1);
        if (dp[l-1][t-1] + blockScore > dp[i][t]) {
          dp[i][t] = dp[l-1][t-1] + blockScore;
          parent[i][t] = l-1;
        }
      }
    }
  }

  // Reconstruct blocks
  const blocks = [];
  let i = n, t = k;
  while (t > 0) {
    const l = parent[i][t] + 1;
    blocks.unshift([l, i]);
    i = l - 1;
    t--;
  }

  return {maxScore: dp[n][k], blocks};
}
```

