function countPaths(grid, K) {
  const m = grid.length;
  const n = grid[0].length;
  if (grid[0][0] === 1 || grid[m-1][n-1] === 1) return 0;

  const dp = Array.from({ length: m }, () =>
    Array.from({ length: n }, () =>
      Array.from({ length: K + 1 }, () => [0, 0])
    )
  );

  dp[0][0][0][0] = 1; // right
  dp[0][0][0][1] = 1; // down

  for (let i = 0; i < m; i++) {
    for (let j = 0; j < n; j++) {
      if (grid[i][j] === 1) continue;
      for (let t = 0; t <= K; t++) {
        // from left (coming from right)
        if (j > 0) {
          dp[i][j][t][0] += dp[i][j-1][t][0]; // same direction
          if (t > 0) dp[i][j][t][0] += dp[i][j-1][t-1][1]; // turn
        }
        // from top (coming from down)
        if (i > 0) {
          dp[i][j][t][1] += dp[i-1][j][t][1]; // same direction
          if (t > 0) dp[i][j][t][1] += dp[i-1][j][t-1][0]; // turn
        }
      }
    }
  }

  let ans = 0;
  for (let t = 0; t <= K; t++) {
    ans += dp[m-1][n-1][t][0] + dp[m-1][n-1][t][1];
  }
  return ans;
}
```

This runs in O(m × n × K) time and O(m × n × K) space.

