function minSumOfBlockMax(A, k) {
  const n = A.length;
  const dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(Infinity));
  const split = Array.from({ length: n + 1 }, () => Array(k + 1).fill(0));

  for (let i = 1; i <= n; i++) {
    dp[i][1] = Math.max(...A.slice(0, i));
  }

  for (let t = 2; t <= k; t++) {
    for (let i = t; i <= n; i++) {
      let maxVal = 0;
      for (let j = i - 1; j >= t - 1; j--) {
        maxVal = Math.max(maxVal, A[j]);
        const cost = dp[j][t - 1] + maxVal;
        if (cost < dp[i][t]) {
          dp[i][t] = cost;
          split[i][t] = j;
        }
      }
    }
  }

  const blocks = [];
  let i = n, t = k;
  while (t > 0) {
    const j = split[i][t];
    blocks.unshift({ start: j + 1, end: i });
    i = j;
    t--;
  }

  return { minSum: dp[n][k], blocks };
}
```

## Why This Problem Is Asked
This question evaluates understanding of dynamic programming on prefixes with a non-crossing pairing constraint. The core challenge is encoding the no-crossing condition by considering the last pair ending at position i with its left partner p.

