function maxPairs(A, k) {
  const n = A.length;
  const NEG = -Infinity;
  const dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(NEG));
  const prev = Array.from({ length: n + 1 }, () => Array(k + 1).fill(null));

  for (let i = 0; i <= n; i++) dp[i][0] = 0;

  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= k; t++) {
      dp[i][t] = dp[i - 1][t];
      prev[i][t] = { skip: true };

      for (let p = 1; p < i; p++) {
        const val = dp[p - 1][t - 1] + A[p - 1] * A[i - 1];
        if (val > dp[i][t]) {
          dp[i][t] = val;
          prev[i][t] = { skip: false, p };
        }
      }
    }
  }

  const pairs = [];
  let i = n, t = k;
  while (i > 0 && t > 0) {
    if (prev[i][t].skip) {
      i--;
    } else {
      const p = prev[i][t].p;
      pairs.push([p, i]);
      i = p - 1;
      t--;
    }
  }

  return { value: dp[n][k], pairs: pairs.reverse() };
}
```

