## Code Example
```javascript
function maxKSubarrays(A, k, c) {
  const n = A.length;
  const prefix = new Array(n + 1).fill(0);
  for (let i = 1; i <= n; i++) prefix[i] = prefix[i - 1] + A[i - 1];

  const dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(-Infinity));
  const prev = Array.from({ length: n + 1 }, () => Array(k + 1).fill(null));
  dp[0][0] = 0;

  for (let i = 1; i <= n; i++) {
    for (let t = 0; t <= k; t++) {
      // Skip element i
      if (dp[i - 1][t] >= dp[i][t]) {
        dp[i][t] = dp[i - 1][t];
        prev[i][t] = { skipped: true };
      }
      // End a block at i
      for (let s = 1; s <= i; s++) {
        const prevIdx = s >= 2 ? s - 2 : 0;
        const val = dp[prevIdx][t - 1] + (prefix[i] - prefix[s - 1]) - c;
        if (val > dp[i][t]) {
          dp[i][t] = val;
          prev[i][t] = { skipped: false, start: s };
        }
      }
    }
  }

  // Reconstruction
  const result = [];
  let i = n, t = k;
  while (i > 0 && t > 0) {
    const state = prev[i][t];
    if (state.skipped) {
      i--;
    } else {
      result.push({ start: state.start, end: i });
      i = state.start - 2;
      t--;
    }
  }
  return { value: dp[n][k], blocks: result.reverse() };
}
```

