function maxSumPartition(s, k){
  const n = s.length;
  const a = s.split('').map(Number);
  const pref = new Array(n+1).fill(0);
  const pow10 = new Array(n+1).fill(1);
  for(let i=1;i<=n;i++){pref[i] = pref[i-1]*10 + a[i-1]; pow10[i] = pow10[i-1]*10;}
  const val = (l,r)=> pref[r]-pref[l-1]*pow10[r-l+1];
  const dp = Array.from({length:n+1},()=>Array(k+1).fill(-Infinity));
  const pre = Array.from({length:n+1},()=>Array(k+1).fill(-1));
  for(let i=1;i<=n;i++){ dp[i][0] = val(1,i); }
  for(let t=1;t<=k;t++){
    for(let i=1;i<=n;i++){
      for(let j=0;j<i;j++){
        if(dp[j][t-1]===-Infinity) continue;
        const cur = dp[j][t-1] + val(j+1,i);
        if(cur>dp[i][t]){ dp[i][t]=cur; pre[i][t]=j; }
      }
    }
  }
  // reconstruct using n and k
  let cuts=[]; let i=n, t=k; while(t>0){ const j=pre[i][t]; cuts.push(j); i=j; t--; }
  cuts.reverse();
  return {sum: dp[n][k], cuts};
}
