  for(let l=0;l<n;l++){
    let mn = A[l], mx = A[l];
    for(let r=l;r<n;r++){
      mn = Math.min(mn, A[r]);
      mx = Math.max(mx, A[r]);
      gain[l][r] = mx - mn;
    }
  }
  const dp = Array.from({length:n+1}, ()=>Array(k+1).fill(-Infinity));
  const take = Array.from({length:n+1}, ()=>Array(k+1).fill(-1));
  dp[0][0] = 0;
