function longestPalindromicSubseqWithDeletions(s, k) {
  const n = s.length;
  const dp = Array.from({ length: n }, () =>
    Array.from({ length: n }, () => Array(k + 1).fill(0))
  );

  for (let i = 0; i < n; i++) {
    for (let d = 0; d <= k; d++) {
      dp[i][i][d] = 1;
    }
  }

  for (let len = 2; len <= n; len++) {
    for (let i = 0; i + len <= n; i++) {
      const j = i + len - 1;
      for (let d = 0; d <= k; d++) {
        if (s[i] === s[j]) {
          dp[i][j][d] = Math.max(dp[i][j][d], (len > 2 ? dp[i + 1][j - 1][d] : 0) + 2);
        }
        if (d > 0) {
          dp[i][j][d] = Math.max(dp[i][j][d], dp[i + 1][j][d - 1], dp[i][j - 1][d - 1]);
        }
      }
    }
  }

  return dp[0][n - 1][k];
}
```

