function maxSumWithGaps(A, gap, k) {
  const n = A.length;
  const NEG = -Infinity;
  const memo = Array.from({ length: n + 2 }, () => Array(k + 1).fill(null));

  const go = (i, r) => {
    if (r === 0) return 0;
    if (i > n) return NEG;
    if (memo[i][r] != null) return memo[i][r];
    const skip = go(i + 1, r);
    const take = A[i - 1] + go(Math.min(n + 1, i + gap[i - 1]), r - 1);
    const best = Math.max(skip, take);
    memo[i][r] = best;
    return best;
  };

  const best = go(1, k);
  return { best, memo };
}
