function maxPartitionDistinct(s, k) {
  const n = s.length;
  const dist = Array.from({ length: n }, () => Array(n).fill(0));

  for (let i = 0; i < n; i++) {
    const seen = new Set();
    for (let j = i; j < n; j++) {
      seen.add(s[j]);
      dist[i][j] = seen.size;
    }
  }

  const dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(-Infinity));
  const prev = Array.from({ length: n + 1 }, () => Array(k + 1).fill(-1));
  dp[0][0] = 0;

  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= Math.min(i, k); t++) {
      for (let j = t - 1; j < i; j++) {
        const val = dp[j][t - 1] + dist[j][i - 1];
        if (val > dp[i][t]) {
          dp[i][t] = val;
          prev[i][t] = j;
        }
      }
    }
  }

  const partitions = [];
  let [i, t] = [n, k];
  while (t > 0) {
    const j = prev[i][t];
    partitions.unshift([j, i - 1]);
    i = j;
    t--;
  }

  return { value: dp[n][k], partitions };
}
```

