function maxKSumIntervals(A, k) {
  const n = A.length;
  const val = Array.from({ length: n }, () => Array(n).fill(0));

  for (let l = 0; l < n; l++) {
    let min = A[l], max = A[l];
    for (let r = l; r < n; r++) {
      min = Math.min(min, A[r]);
      max = Math.max(max, A[r]);
      val[l][r] = max - min;
    }
  }

  const dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(-Infinity));
  const parent = Array.from({ length: n + 1 }, () => Array(k + 1).fill(null));

  for (let i = 0; i <= n; i++) dp[i][0] = 0;

  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= k; t++) {
      dp[i][t] = dp[i-1][t];
      parent[i][t] = { skip: true };

      for (let j = 1; j <= i; j++) {
        const prev = j >= 2 ? dp[j-2][t-1] : (t === 1 ? 0 : -Infinity);
        if (prev === -Infinity) continue;
        const curr = prev + val[j-1][i-1];
        if (curr > dp[i][t]) {
          dp[i][t] = curr;
          parent[i][t] = { start: j, end: i, prev: j - 2 };
        }
      }
    }
  }

  const intervals = [];
  let i = n, t = k;
  while (t > 0 && parent[i][t]) {
    const p = parent[i][t];
    if (!p.skip) {
      intervals.push([p.start, p.end]);
      i = p.prev;
      t--;
    } else {
      i--;
    }
  }

  return { maxValue: dp[n][k], intervals: intervals.reverse() };
}
```

