  for (let i = 0; i <= n; i++) dp[i][0] = 0;

  for (let i = 1; i <= n; i++) {
    for (let j = 1; j <= Math.min(m, Math.floor((i + 1) / 2)); j++) {
      const take = A[i - 1] + (i >= 2 ? dp[i - 2][j - 1] : (j - 1 === 0 ? 0 : NEG));
      const skip = dp[i - 1][j];
      dp[i][j] = Math.max(skip, take);
    }
  }

  const result = dp[n][m];
  const indices = [];
  let i = n, j = m;

  while (i > 0 && j > 0) {
    const take = A[i - 1] + (i >= 2 ? dp[i - 2][j - 1] : (j - 1 === 0 ? 0 : NEG));
    if (dp[i][j] === take) {
      indices.push(i - 1);
      j--;
      i -= 2;
    } else {
      i--;
    }
  }

  return { sum: result, indices: indices.reverse() };
}
