- Precomputing p[i] via binary search for O(log n) lookups
- Backtracking through DP table for reconstruction

## Code Example
```javascript
function weightedIntervalScheduling(tasks, K) {
  // Sort by end time
  tasks.sort((a, b) => a.end - b.end);
  const n = tasks.length;

  // Precompute p[i] - last non-overlapping task
  const ends = tasks.map(t => t.end);
  const p = new Array(n).fill(0);
  for (let i = 0; i < n; i++) {
    let lo = 0, hi = i - 1, res = -1;
    while (lo <= hi) {
      const mid = Math.floor) / 2((lo + hi);
      if (tasks[mid].end <= tasks[i].start) {
        res = mid;
        lo = mid + 1;
      } else {
        hi = mid - 1;
      }
    }
    p[i] = res;
  }

  // DP table: dp[i][t] = max value using first i tasks for t selections
  const dp = Array.from({ length: n + 1 }, () => Array(K + 1).fill(0));

  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= K; t++) {
      // Skip task i-1
      dp[i][t] = dp[i - 1][t];
      // Take task i-1
      if (p[i - 1] !== -1) {
        dp[i][t] = Math.max(dp[i][t], dp[p[i - 1] + 1][t - 1] + tasks[i - 1].value);
      } else if (t === 1) {
        dp[i][t] = Math.max(dp[i][t], tasks[i - 1].value);
      }
    }
  }

  // Reconstruction
  const chosen = [];
  let i = n, t = K;
  while (i > 0 && t > 0) {
    if (dp[i][t] === dp[i - 1][t]) {
      i--;
    } else {
      chosen.push(i - 1);
      const prev = p[i - 1];
      i = prev + 1;
      t--;
    }
  }

  return { maxValue: dp[n][K], chosenTasks: chosen.reverse() };
}
```

