function maxPalPartitionScore(s, k) {
  const n = s.length;
  const isPal = Array.from({length: n}, () => Array(n).fill(false));
  const dist = Array.from({length: n}, () => Array(n).fill(0));

  for (let i = 0; i < n; i++) { isPal[i][i] = true; dist[i][i] = 1; }
  for (let len = 2; len <= n; len++) {
    for (let i = 0; i + len - 1 < n; i++) {
      const j = i + len - 1;
      if (s[i] === s[j] && (len === 2 || isPal[i+1][j-1])) isPal[i][j] = true;
      const seen = new Set();
      for (let p = i; p <= j; p++) seen.add(s[p]);
      dist[i][j] = seen.size;
    }
  }

  const dp = Array.from({length: n+1}, () => Array(k+1).fill(-Infinity));
  const par = Array.from({length: n+1}, () => Array(k+1).fill(-1));
  dp[0][0] = 0;
  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= Math.min(i, k); t++) {
      for (let j = 0; j < i; j++) {
        if (isPal[j][i-1] && dp[j][t-1] > -Infinity) {
          const cand = dp[j][t-1] + dist[j][i-1];
          if (cand > dp[i][t]) { dp[i][t] = cand; par[i][t] = j; }
        }
      }
    }
  }

  // reconstruct cuts
  const cuts = [];
  let i = n, t = k;
  while (t > 0) {
    const j = par[i][t];
    cuts.push([j, i]);
    i = j; t--;
  }
  cuts.reverse();
  return { score: dp[n][k], cuts };
}
```

