    let best = NEG;
    for (let i=1; i<=n; i++) {
      const val = dp[i-1][t-1] - S[i-1] + c*(i-1);
      if (val > best) { best = val; }
      const cand = S[i] - c*i + best;
      if (cand > dp[i][t]) { dp[i][t] = cand; prv[i][t] = i; }
      if (dp[i-1][t] > dp[i][t]) { dp[i][t] = dp[i-1][t]; prv[i][t] = -1; }
    }
  }
  // reconstruct (simple backtrack)
  const intervals = [];
  let i = n, t = k;
  while (t > 0 && i > 0) {
    if (prv[i][t] === -1) { i--; continue; }
    const end = i;
    const start = prv[i][t];
    intervals.push([start, end]);
    i = start - 1; t--;
  }
  intervals.reverse();
  return { value: dp[n][k], intervals };
}
```

## Follow-up Questions

- How would you extend to allow variable per-interval cost or rewards based on length?
- How would you optimize memory to O(nk) and still reconstruct intervals?

## Why This Is Asked
Tests dynamic programming with a non-adjacency constraint and explicit reconstruction of the deletion indices.

## Key Concepts
- DP with two states per index to enforce non-adjacency
- Exact deletions constraint (k) and reconstruction
- O(nk) time and O(nk) space (can optimize to O(k) with rolling arrays)

## Code Example
```javascript
function maxSumAfterDeletions(A, k) {
  const n = A.length;
  const NEG = -1e15;
  const keep = Array.from({length: n}, () => Array(k+1).fill(NEG));
  const del = Array.from({length: n}, () => Array(k+1).fill(NEG));
  keep[0][0] = A[0];
  if (k >= 1) del[0][1] = 0;
  for (let i = 1; i < n; i++) {
    for (let t = 0; t <= k; t++) {
      keep[i][t] = Math.max(keep[i-1][t], del[i-1][t]);
      if (keep[i][t] > NEG/2) keep[i][t] += A[i];
      if (t > 0) del[i][t] = keep[i-1][t-1];
    }
  }
  const end = Math.max(keep[n-1][k], del[n-1][k]);
  // Backtracking to collect deleted indices would be added here
  return {maxSum: end, deletedIndices: []};
}
```

## Follow-up Questions
