// Pseudocode illustrating transitions
for i in 1..n:
  for t in 0..k:
    for r in 0..L-1:
      // skip
      dp[i][t][r] = Math.max(dp[i][t][r], dp[i-1][t][r])
      // take
      if (r==0 && t<=k) {
        dp[i][t][1] = Math.max(dp[i][t][1], dp[i-1][t][0] + A[i])
      } else if (r>0 && r<L-1) {
        dp[i][t][r+1] = Math.max(dp[i][t][r+1], dp[i-1][t][r] + A[i])
      } else if (r==L-1) {
        dp[i][t+1][0] = Math.max(dp[i][t+1][0], dp[i-1][t][L-1] + A[i])
      }
