// Pseudo-code for k vertex-disjoint path selection

function selectKPaths(N, M, edges, weights, k) {
  const dp = Array(N).fill(null).map(() => Array(k + 1).fill(-Infinity));
  const parent = Array(N).fill(null).map(() => Array(k + 1).fill(null));

  // Get topological order
  const topo = topologicalSort(N, edges);

  // Initialize sources
  for (const s of sources) {
    dp[s][1] = weights[s];
  }

  // Process in topological order
  for (const u of topo) {
    for (const v of adj[u]) {
      for (let t = 1; t < k; t++) {
        if (dp[u][t] > -Infinity) {
          const newWeight = dp[u][t] + weights[v];
          if (newWeight > dp[v][t + 1]) {
            dp[v][t + 1] = newWeight;
            parent[v][t + 1] = u;
          }
        }
      }
    }
  }

  // Reconstruct paths using parent pointers
  return reconstructPaths(dp, parent, k);
}
```

