    let m = -Infinity;
    for (let r = l; r < n; r++) {
      m = Math.max(m, A[r]);
      maxSub[l][r] = m;
    }
  }
  const dp = Array.from({length: n+1}, () => Array(k+1).fill(0));
  const take = Array.from({length: n+1}, () => Array(k+1).fill(-1));
  for (let i = 1; i <= n; i++) {
