      dp[i][t] = best; take[i][t] = bestJ;
    }
  }
  const res = [];
  let i = n, t = k;
  while (t > 0 && i > 0) {
    const j = take[i][t];
    if (j === -1) break;
    res.push([j-1, i-1]);
    i = j - 1;
    t--;
  }
  res.reverse();
  return {value: dp[n][k], subarrays: res};
