  const n = arr.length;
  const pref = Array(n+1).fill(0);
  for(let i=1;i<=n;i++) pref[i] = pref[i-1] + arr[i-1];
  const dp = Array.from({length: n+1}, ()=> Array(k+1).fill(-Infinity));
  const opt = Array.from({length: n+1}, ()=> Array(k+1).fill(-1));
  dp[0][0] = 0;
  for(let i=1;i<=n;i++){
    for(let t=1;t<=Math.min(i,k);t++){
      for(let p=t-1;p<=i-1;p++){
        const val = dp[p][t-1] + (pref[i]-pref[p])*(pref[i]-pref[p]);
        if(val > dp[i][t]){ dp[i][t] = val; opt[i][t] = p; }
