function maxValueKJobs(jobs, k) {
  const sorted = jobs.map((j, idx) => ({ ...j, idx })).sort((a, b) => a.end - b.end);
  const n = sorted.length;
  const ends = sorted.map(j => j.end);

  const p = (i) => {
    let lo = 0, hi = i - 1;
    while (lo <= hi) {
      const mid = Math.floor((lo + hi) / 2);
      if (ends[mid] <= sorted[i].start) lo = mid + 1;
      else hi = mid - 1;
    }
    return hi;
  };

  const dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(0));
  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= k; t++) {
      const prev = p(i - 1) + 1;
      dp[i][t] = Math.max(dp[i - 1][t], dp[prev][t - 1] + sorted[i - 1].value);
    }
  }

  const selected = [];
  let t = k;
  for (let i = n; i > 0 && t > 0; i--) {
    if (dp[i][t] !== dp[i - 1][t]) {
      selected.push(sorted[i - 1]);
      t--;
    }
  }

  return { value: dp[n][k], jobs: selected.reverse() };
}
```

