  // reconstruction (simple version)
  let i=n, t=k, ends=[];
  while(t>0){
    const [pi, pt] = par[i][t] || [-1,-1];
    if(pi===-1) break;
    // approximate end at i, start at some m where dp[m][t-1]-S[m] was max
    // for brevity here, return only values; full reconstruction can be added as needed
    ends.push(i);
    i = pi; t--;
