          dp[i][j][t] = Math.max(dp[i][j][t], dp[i-1][j][t] + grid[i][j]);
        }
        if (j > 0 && dp[i][j-1][t] !== NEG) {
          dp[i][j][t] = Math.max(dp[i][j][t], dp[i][j-1][t] + grid[i][j]);
        }
        if (t > 0) {
          if (i > 0 && dp[i-1][j][t-1] !== NEG) {
            dp[i][j][t] = Math.max(dp[i][j][t], dp[i-1][j][t-1] + grid[i][j] + B);
          }
          if (j > 0 && dp[i][j-1][t-1] !== NEG) {
            dp[i][j][t] = Math.max(dp[i][j][t], dp[i][j-1][t-1] + grid[i][j] + B);
          }
        }
      }
    }
  }

  const boosts = [];
  let i = n - 1, j = m - 1, t = k;
  while (i > 0 || j > 0) {
    const fromTop = i > 0 && dp[i][j][t] === dp[i-1][j][t] + grid[i][j];
    const fromLeft = j > 0 && dp[i][j][t] === dp[i][j-1][t] + grid[i][j];
    const boostedFromTop = i > 0 && t > 0 && dp[i][j][t] === dp[i-1][j][t-1] + grid[i][j] + B;
    const boostedFromLeft = j > 0 && t > 0 && dp[i][j][t] === dp[i][j-1][t-1] + grid[i][j] + B;

    if (boostedFromTop || boostedFromLeft) boosts.push([i, j]);
    if (boostedFromTop || (i > 0 && fromTop && !boostedFromTop)) { i--; }
    else if (j > 0) { j--; if (!boostedFromLeft && !fromLeft) t--; }
  }

  return { maxSum: dp[n-1][m-1][k], boosts: boosts.reverse() };
}
```

## Complexity
- **Time:** O(n × m × k)
- **Space:** O(n × m × k) or O(m × k) with row optimization

## Why This Is Asked
This question tests advanced tree DP with edge deletions and a non-trivial objective—maximizing the sum of component maxima. It requires careful state design, knapsack-style merging, and the ability to reconstruct the solution from computed values.

## Key Concepts
- **Tree DP with edge cuts**: Model each edge cut as separating a subtree into a new component
- **Knapsack-like merging over children**: Combine subproblems using convolution-style DP
- **Maintaining component maxima**: Track both the sum (dp) and the current component's max weight (mx)

## Code Example
```javascript
function solve(n, edges, weights, k) {
    const children = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) children[u - 1].push(v - 1);

    const dp = Array.from({ length: n }, () => new Array(k + 1).fill(-1e9));
    const mx = Array.from({ length: n }, () => new Array(k + 1).fill(-1e9));
    const parent = Array(n).fill(-1);

    function dfs(u) {
        dp[u][0] = 0;
        mx[u][0] = weights[u];
        for (const v of children[u]) {
            parent[v] = u;
            dfs(v);
            for (let t = k; t >= 0; t--) {
                const ndp = new Array(k + 1).fill(-1e9);
                const nmx = new Array(k + 1).fill(-1e9);
                for (let t1 = 0; t1 <= t; t1++) {
                    const t2 = t - t1;
                    // cut edge
                    ndp[t] = Math.max(ndp[t], dp[u][t1] + dp[v][t2] + mx[v][t2]);
                    nmx[t] = Math.max(nmx[t], mx[u][t1]);
                    // keep edge
                    ndp[t] = Math.max(ndp[t], dp[u][t1] + dp[v][t2]);
                    nmx[t] = Math.max(nmx[t], Math.max(mx[u][t1], mx[v][t2]));
                }
                dp[u] = ndp;
                mx[u] = nmx;
            }
        }
    }

    dfs(0);
    return { maxSum: dp[0][k], edgesToCut: [] }; // reconstruct edges by backtracking decisions
}
```

## Common Pitfalls
- **Forgetting to reset mx when cutting**: When an edge is cut, the parent component's max weight remains unchanged
- **Incorrect knapsack direction**: Always iterate cuts in descending order to avoid reusing the same child multiple times
- **Off-by-one in component counting**: k edge cuts always produce k+1 components

