function maxKSubarrays(A, k, p) {
  const n = A.length;
  const negInf = -1e18;
  const local = Array.from({ length: n + 1 }, () => Array(k + 1).fill(negInf));
  const global = Array.from({ length: n + 1 }, () => Array(k + 1).fill(negInf));
  global[0][0] = 0;
