## Code Example

```javascript
function minSumPartition(s, k) {
  const n = s.length;

  // Helper to get numeric value of substring [l, r)
  const getValue = (l, r) => {
    if (s[l] === '0' && r - l > 1) return null; // leading zero
    return Number(s.slice(l, r));
  };

  const dp = Array(n + 1).fill().map(() => Array(k + 1).fill(Infinity));
  const parent = Array(n + 1).fill().map(() => Array(k + 1).fill(-1));

  dp[0][0] = 0;

  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= k; t++) {
      for (let j = t - 1; j < i; j++) {
        const val = getValue(j, i);
        if (val !== null && dp[j][t-1] + val < dp[i][t]) {
          dp[i][t] = dp[j][t-1] + val;
          parent[i][t] = j;
        }
      }
    }
  }

  // Reconstruct cuts
  const cuts = [];
  let curr = n, currT = k;
  while (currT > 0) {
    const prev = parent[curr][currT];
    cuts.push(prev);
    curr = prev;
    currT--;
  }
  cuts.pop(); // remove 0
  cuts.reverse();

  return { minSum: dp[n][k], cuts };
}
```

## Notes

- The DP explores all possible cut positions while respecting the k-substring constraint
- Leading zero validation is crucial for correctness
- The parent array enables O(k) reconstruction of optimal cuts

