```javascript
function maxValueBlocks(A, k) {
  const n = A.length;
  const dp = Array.from({length: n+1}, () => Array(k+1).fill(-Infinity));
  const pre = Array.from({length: n+1}, () => Array(k+1).fill(-1));

  dp[0][0] = 0;

  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= Math.min(k, i); t++) {
      let currentMin = Infinity;
      for (let p = i; p >= t; p--) {
        currentMin = Math.min(currentMin, A[p-1]);
        const candidate = (dp[p-1][t-1] + currentMin * (i-p+1));
        if (candidate > dp[i][t]) {
          dp[i][t] = candidate;
          pre[i][t] = p;
        }
      }
    }
  }

  // Reconstruct solution
  const blocks = [];
  let i = n, t = k;
  while (t > 0) {
    const p = pre[i][t];
    blocks.unshift([p, i]);
    i = p - 1;
    t--;
  }

  return { maxValue: dp[n][k], blocks };
}
```

