function minCostPath(grid, K) {
  const n = grid.length, m = grid[0].length;
  const INF = 1e15;
  const dp = Array.from({ length: n }, () => Array.from({ length: m }, () => Array(K+1).fill(INF)));
  const parent = Array.from({ length: n }, () => Array.from({ length: m }, () => Array(K+1).fill(null)));
  dp[0][0][0] = grid[0][0];
  for (let i = 0; i < n; i++) {
    for (let j = 0; j < m; j++) {
      for (let t = 0; t <= K; t++) {
        if (i === 0 && j === 0 && t === 0) continue;
        let best = INF, pick = null;
        if (i > 0 && dp[i-1][j][t] < best) { best = dp[i-1][j][t]; pick = [i-1, j, t]; }
        if (j > 0 && dp[i][j-1][t] < best) { best = dp[i][j-1][t]; pick = [i, j-1, t]; }
        if (i > 0 && j > 0 && t > 0 && dp[i-1][j-1][t-1] < best) { best = dp[i-1][j-1][t-1]; pick = [i-1, j-1, t-1]; }
        if (best < INF) {
          dp[i][j][t] = best + grid[i][j];
          if (pick) parent[i][j][t] = pick;
        }
      }
    }
  }
  // find best end state
  let bestCost = INF, endT = 0;
  for (let t = 0; t <= K; t++) {
    if (dp[n-1][m-1][t] < bestCost) { bestCost = dp[n-1][m-1][t]; endT = t; }
  }
  // reconstruct path
  const path = [];
  let i = n-1, j = m-1, t = endT;
  while (i !== 0 || j !== 0 || t !== 0) {
    path.push([i, j]);
    const p = parent[i][j][t];
    if (!p) break;
    [i, j, t] = p;
  }
  path.push([0,0]);
  path.reverse();
  return { cost: bestCost, path };
}
```

