function maxMinSubarrayVal(arr){
  const n = arr.length;
  const maxVal = Array.from({length:n}, ()=>Array(n).fill(0));
  const minVal = Array.from({length:n}, ()=>Array(n).fill(0));
  for(let i=0;i<n;i++){
    let curMax = arr[i], curMin = arr[i];
    for(let j=i;j<n;j++){
      curMax = Math.max(curMax, arr[j]);
      curMin = Math.min(curMin, arr[j]);
      maxVal[i][j] = curMax;
      minVal[i][j] = curMin;
    }
  }
  const val = (l,r)=> maxVal[l][r] - minVal[l][r];
  return val;
}

function bestPartition(arr, k){
  const n = arr.length;
  const val = maxMinSubarrayVal(arr);
  const dp = Array.from({length:n+1}, ()=>Array(k+1).fill(-Infinity));
  const parent = Array.from({length:n+1}, ()=>Array(k+1).fill(-1));
  for(let i=1;i<=n;i++) dp[i][1] = val(0,i-1);
  for(let t=2;t<=k;t++){
    for(let i=t;i<=n;i++){
      for(let j=t-1;j<=i-1;j++){
        const cand = dp[j][t-1] + val(j, i-1);
        if(cand > dp[i][t]){ dp[i][t] = cand; parent[i][t]=j; }
      }
    }
  }
  // reconstruct
  let blocks = [];
  let i=n, t=k;
  while(t>0){
    const j = parent[i][t];
    blocks.push([j, i-1]);
    i = j; t--;
