```javascript
function minCostPartition(A, k){
  const n = A.length;
  const pref = new Array(n+1).fill(0);
  for(let i=0;i<n;i++) pref[i+1] = pref[i] + A[i];
  const INF = 1e15;
  const dp = Array.from({length:n+1}, ()=>Array(k+1).fill(INF));
