    for(let t=1;t<=Math.min(i,k);t++){
      for(let p=t-1;p<=i-1;p++){
        const sum = pref[i]-pref[p];
        const len = i-p;
        const cost = Math.floor(sum/len);
        if(dp[p][t-1] + cost < dp[i][t]){
          dp[i][t] = dp[p][t-1] + cost;
          par[i][t] = p;
        }
      }
    }
