    dp[i][1] = P[i];
  }

  for (let t = 2; t <= k; t++) {
    for (let i = t; i <= n; i++) {
      for (let p = t-1; p < i; p++) {
        const score = dp[p][t-1] + (P[i] - P[p]) * t;
        if (score > dp[i][t]) {
          dp[i][t] = score;
          parent[i][t] = p;
        }
