```javascript
function maxKSubarrays(A, k){
  const n = A.length;
  const pref = Array(n+1).fill(0);
  for(let i=0;i<n;i++) pref[i+1] = pref[i] + A[i];
  const V = Array.from({length:n}, ()=> Array(n).fill(0));
  for(let l=0;l<n;l++){
    let mn = Infinity;
    for(let r=l;r<n;r++){
      mn = Math.min(mn, A[r]);
      const sum = pref[r+1]-pref[l];
      V[l][r] = sum * mn;
    }
  }
  const NEG = -1e18;
  const dp = Array.from({length:n+1}, ()=> Array(k+1).fill(NEG));
  const pre = Array.from({length:n+1}, ()=> Array(k+1).fill(-1));
  dp[0][0] = 0;
  for(let i=1;i<=n;i++) dp[i][0] = NEG;
  for(let i=1;i<=n;i++){
    for(let t=1;t<=k;t++){
      dp[i][t] = dp[i-1][t];
      pre[i][t] = pre[i-1][t];
      for(let j=0;j<i;j++){
        const val = dp[j][t-1] + V[j][i-1];
        if(val > dp[i][t]){ dp[i][t] = val; pre[i][t] = j; }
      }
    }
  }
  let blocks = [];
  let i = n, t = k;
  while(t>0){
    const j = pre[i][t];
    blocks.push([j, i-1]);
    i = j; t--;
  }
  blocks.reverse();
  return { value: dp[n][k], blocks };
}
```

