function maxKSubarraysWithCost(A, k, c) {
  const n = A.length;
  const B = A.map(x => x - c);
  const end = Array.from({length: n+1}, () => Array(k+1).fill(-Infinity));
  const best = Array.from({length: n+1}, () => Array(k+1).fill(-Infinity));
  const prevEnd = Array.from({length: n+1}, () => Array(k+1).fill(null));

  best[0][0] = 0;
  for (let i = 1; i <= n; i++) {
    end[i][0] = -Infinity;
    best[i][0] = 0;
    for (let t = 1; t <= k; t++) {
      const extend = end[i-1][t] + B[i-1];
      const startNew = best[i-1][t-1] + B[i-1];
      end[i][t] = Math.max(extend, startNew);
      if (best[i-1][t] >= end[i][t]) {
        best[i][t] = best[i-1][t];
      } else {
        best[i][t] = end[i][t];
        prevEnd[i][t] = true;
      }
    }
  }

  let bestVal = -Infinity, bestT = 0;
  for (let t = 0; t <= k; t++) {
    if (best[n][t] > bestVal) { bestVal = best[n][t]; bestT = t; }
  }
