function linearDP(arr, d){
  const n = arr.length; const dp = Array(n+1).fill(0); const ways = Array(n+1).fill(0);
  dp[0] = 0; ways[0] = 1;
  for(let i=1;i<=n;i++){
    const take = arr[i-1] + (i-d>=0 ? dp[i-d] : 0);
    const skip = dp[i-1];
    if(take>skip){ dp[i]=take; ways[i]=(i-d>=0 ? ways[i-d] : 1); }
    else if(take<skip){ dp[i]=skip; ways[i]=ways[i-1]; }
    else { dp[i]=skip; ways[i] = ((i-d>=0 ? ways[i-d] : 1) + ways[i-1]); }
  }
  return [dp[n], ways[n]];
}

function maxCircular(v, d){
  const [bestA, cntA] = linearDP(v.slice(1), d); // exclude first
  const n = v.length;
  const seg = (n > 2*d-1) ? v.slice(d, n-d+1) : [];
  const [bestBseg, cntBseg] = seg.length ? linearDP(seg, d) : [0,1];
  const bestB = v[0] + bestBseg;
  if(bestA > bestB) return [bestA, cntA];
  if(bestB > bestA) return [bestB, cntBseg];
  return [bestA, cntA + cntBseg];
}
```

