function maxOrPartition(A, k) {
  const n = A.length;
  const OR = Array.from({length: n+1}, () => Array(n+1).fill(0));

  // Precompute OR for all subarrays
  for (let i = 0; i < n; i++) {
    let cur = 0;
    for (let j = i; j < n; j++) {
      cur |= A[j];
      OR[i][j+1] = cur;
    }
  }

  const dp = Array.from({length: n+1}, () => Array(k+1).fill(-Infinity));
  const par = Array.from({length: n+1}, () => Array(k+1).fill(-1));

  dp[0][0] = 0;

  for (let t = 1; t <= k; t++) {
    for (let i = 1; i <= n; i++) {
      for (let j = 0; j < i; j++) {
        if (dp[j][t-1] !== -Infinity) {
          const val = dp[j][t-1] + OR[j][i];
          if (val > dp[i][t]) {
            dp[i][t] = val;
            par[i][t] = j;
          }
        }
      }
    }
  }

  // Reconstruct blocks
  const blocks = [];
  let curr = n;
  for (let t = k; t >= 1; t--) {
    const start = par[curr][t];
    blocks.unshift([start, curr-1]);
    curr = start;
  }

  return { maxSum: dp[n][k], blocks };
}
```

