function maxScore(nums, m) {
  const n = nums.length;
  const dp = Array.from({length: n+1}, ()=> Array(m+1).fill(-Infinity));
  const par = Array.from({length: n+1}, ()=> Array(m+1).fill(-1));
  dp[0][0] = 0;
  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= Math.min(i, m); t++) {
