    for (let j = 0; j < m; j++) {
      for (let t = 0; t <= k; t++) {
        if (j > 0) {
          const fromLeftSame = dp[i][j-1][t][0];
          const fromLeftTurn = t > 0 ? dp[i][j-1][t-1][1] : NEG;
          dp[i][j][t][0] = Math.max(dp[i][j][t][0], grid[i][j] + Math.max(fromLeftSame, fromLeftTurn));
        }
        if (i > 0) {
          const fromTopSame = dp[i-1][j][t][1];
          const fromTopTurn = t > 0 ? dp[i-1][j][t-1][0] : NEG;
          dp[i][j][t][1] = Math.max(dp[i][j][t][1], grid[i][j] + Math.max(fromTopSame, fromTopTurn));
        }
      }
    }
  }
  let best = NEG, bestT = 0, bestDir = 0;
  for (let t = 0; t <= k; t++) {
