function computeBestStartDP(A, k) {
  const n = A.length;
  const pref = Array(n+1).fill(0);
  for (let i=0;i<n;i++) pref[i+1] = pref[i] + A[i];
  const bestStart = Array.from({length:n}, ()=> Array(n).fill(-Infinity));
  for (let l=0; l<n; l++) {
    let best = -Infinity;
    for (let i=l; i<n; i++) {
      const sum = pref[i+1]-pref[l];
      best = Math.max(best, sum);
      bestStart[l][i] = best;
    }
  }
  const dp = Array.from({length:n}, ()=> Array(k+1).fill(-Infinity));
  const par = Array.from({length:n}, ()=> Array(k+1).fill(-1));
  for (let i=0; i<n; i++) dp[i][1] = bestStart[0][i];
  for (let t=2; t<=k; t++) {
    for (let i=t-1; i<n; i++) {
      let bestVal = -Infinity, bestL = -1;
      for (let l=t-1; l<=i; l++) {
        const prev = (l-1>=0) ? dp[l-1][t-1] : (t-1===0 ? 0 : -Infinity);
        const val = prev + bestStart[l][i];
        if (val > bestVal) { bestVal = val; bestL = l; }
      }
      dp[i][t] = bestVal;
      par[i][t] = bestL;
    }
  }
  return {dp, par};
}
```

